// O(1) lookup map — avoids races.find(r => r.label === X) linear scans across
// 35+ races for hot paths in spin/battle/character build code.
export const racesByLabel: Map<string, Race> = new Map(races.map(r => [r.label, r]))
export const getRace = (label: string | undefined | null): Race | undefined =>
  label ? racesByLabel.get(label) : undefined

// ── Content augmentation (runs once at module load, before the lookups) ──────
// 1. Rarer racial spin outcomes (weight ≤ 2) that don't already grant stats get
//    a derived stat boost/debuff — so the rare ones DO something beyond their
//    wheel effect, for every race. The rarest (weight 1) grant two; "dark"
//    elements buy power with a stat PENALTY.
// 2. Every racial ability inherits an element + grade from its parent pool
//    entry when missing, so each fires a meaningful elemental projectile/beam.
const _ELEMENT_STATS: Record<string, [string, string]> = {
  Fire: ['strength', 'durability'], Earth: ['durability', 'strength'], Metal: ['durability', 'fightingSkill'],
  Lightning: ['speed', 'energyLevel'], Wind: ['agility', 'speed'], Water: ['agility', 'potential'],
  Arcane: ['powerMastery', 'iq'], Cosmic: ['powerMastery', 'potential'], Time: ['speed', 'iq'],
  Psychic: ['iq', 'powerMastery'], Soul: ['potential', 'charisma'], Void: ['powerMastery', 'potential'],
  Light: ['charisma', 'potential'], Sound: ['charisma', 'iq'], Nature: ['potential', 'durability'],
  Shadow: ['agility', 'powerMastery'], Poison: ['durability', 'agility'], Chaos: ['potential', 'powerMastery'],
  Blood: ['strength', 'durability'], Neutral: ['fightingSkill', 'strength'],
}
const _DARK_ELEMENTS = new Set(['Shadow', 'Void', 'Blood', 'Chaos', 'Poison'])

function _deriveStatGrants(element: string | undefined, weight: number): Record<string, 'statBonus' | 'statPenalty'> {
  const [a, b] = _ELEMENT_STATS[element ?? 'Neutral'] ?? _ELEMENT_STATS.Neutral
  const grants: Record<string, 'statBonus' | 'statPenalty'> = { [a]: 'statBonus' }
  if (weight <= 1) grants[b] = _DARK_ELEMENTS.has(element ?? '') ? 'statPenalty' : 'statBonus'
  return grants
}

type _AugPoolEntry = {
  label: string
  weight: number
  element?: import('./types').ElementType
  grade?: import('./types').ItemGrade
  statBonusGrants?: Record<string, 'statBonus' | 'statPenalty'>
  grantedPowers?: string[]
  bonusSpins?: { category: string; displayName: string }[]
  powerPool?: { label: string; weight: number }[]
  abilities?: Array<{ element?: import('./types').ElementType; grade?: import('./types').ItemGrade }>
}
for (const race of races) {
  for (const pool of [race.subTypePool, race.classPool, race.transformationPool]) {
    for (const entry of (pool ?? []) as _AugPoolEntry[]) {
      // EVERY racial progression outcome (sub-type / class / transformation)
      // grants a reward so no spin goes unrewarded. Rarer outcomes (weight ≤ 2)
      // get the exciting variety — a signature power/ability, a bonus
      // weapon/armor spin, or (rarest) an innate weakness alongside a stat
      // boost. Commoner outcomes still grant a solid stat boost. Entries that
      // already define a reward are left untouched.
      const hasReward = entry.statBonusGrants || entry.grantedPowers?.length || entry.bonusSpins?.length
      if (!hasReward) {
        const seed = entry.label.length + (entry.label.charCodeAt(0) ?? 0) + (entry.label.charCodeAt(entry.label.length - 1) ?? 0)
        const sig = entry.powerPool?.length ? entry.powerPool[entry.powerPool.length - 1].label : null
        if (entry.weight <= 2) {
          switch (seed % 5) {
            case 0:
              if (sig) { entry.grantedPowers = [sig]; break }
              entry.statBonusGrants = _deriveStatGrants(entry.element, entry.weight); break
            case 1:
              entry.bonusSpins = [{ category: 'weapon', displayName: 'Signature Weapon' }]; break
            case 2:
              entry.bonusSpins = [{ category: 'armor', displayName: 'Natural Armor' }]; break
            case 3:
              entry.bonusSpins = entry.weight <= 1
                ? [{ category: 'weakness', displayName: 'Innate Flaw' }]
                : [{ category: 'armor', displayName: 'Natural Armor' }]
              break
            default:
              entry.statBonusGrants = _deriveStatGrants(entry.element, entry.weight)
          }
        } else {
          // Common outcome — a single thematic stat boost (no penalty).
          const [stat] = _ELEMENT_STATS[entry.element ?? 'Neutral'] ?? _ELEMENT_STATS.Neutral
          entry.statBonusGrants = { [stat]: 'statBonus' }
        }
      }
      for (const ab of entry.abilities ?? []) {
        if (!ab.element) ab.element = entry.element ?? 'Neutral'
        if (!ab.grade) ab.grade = entry.grade ?? 'C'
      }
    }
  }
  for (const ab of (race.abilities ?? []) as Array<{ element?: import('./types').ElementType; grade?: import('./types').ItemGrade }>) {
    if (!ab.element) ab.element = 'Neutral'
    if (!ab.grade) ab.grade = 'C'
  }
  // Race-specific injected wheels (e.g. Dragon Aspect / Breath Evolution) —
  // every segment grants a stat boost/debuff so these progression spins are
  // rewarding too. (Segments support statBonusGrants; applied by the hosts.)
  for (const wheel of race.injectedWheels ?? []) {
    for (const seg of wheel.segments as Array<{ weight: number; element?: import('./types').ElementType; statBonusGrants?: Record<string, 'statBonus' | 'statPenalty'> }>) {
      if (!seg.statBonusGrants) {
        seg.statBonusGrants = seg.weight <= 2
          ? _deriveStatGrants(seg.element, seg.weight)
          : { [(_ELEMENT_STATS[seg.element ?? 'Neutral'] ?? _ELEMENT_STATS.Neutral)[0]]: 'statBonus' }
      }
    }
  }
}

// Flat lookup from every race subType/class/transformation entry → element + grade.
// Previously rebuilt at +page.svelte module init on every page load; lifting it here
// means the Map is computed once when the races chunk is loaded.
type _PoolEntry = { element?: import('./types').ElementType; grade?: import('./types').ItemGrade }
export const racePoolLookup: Map<string, _PoolEntry> = (() => {
  const m = new Map<string, _PoolEntry>()
  for (const race of races) {
    const entries: { label: string; element?: import('./types').ElementType; grade?: import('./types').ItemGrade }[] = [
      ...(race.subTypePool ?? []),
      ...(race.classPool ?? []),
      ...(race.transformationPool ?? []),
    ]
    for (const entry of entries) {
      if (entry.element || entry.grade) m.set(entry.label, { element: entry.element, grade: entry.grade })
    }
  }
  return m
})()

// Canonical label → element/grade for the global powers content. Populated
// by powers.ts via _registerPowersForLookup once that module's `powers`
// constant has finished initializing — pulling powers directly here would
// load the (very large) absurd/epic chunks just to build a map that the
// race-pooled lookup might never read. The map is module-scoped, so any
// subsequent racePowerLookup .get() sees the registered entries.
const _powersGlobalLookup = new Map<string, _PoolEntry>()
export function _registerPowersForLookup(
  list: { label: string; element?: import('./types').ElementType; grade?: import('./types').ItemGrade }[],
) {
  for (const p of list) {
    if ((p.element || p.grade) && !_powersGlobalLookup.has(p.label)) {
      _powersGlobalLookup.set(p.label, { element: p.element, grade: p.grade })
    }
  }
}

// Race-pooled power label → element/grade. Inherits in this priority order:
//   1. The entry's own element/grade (if it supplied them).
//   2. The global powers content pool (canonical source for shared labels).
//   3. The parent class/subtype/transformation's element/grade.
// Lazy-built on first read because the global powers pool registers itself
// via _registerPowersForLookup AFTER this module has finished initializing
// (powers.ts imports from races.ts but not vice-versa). Building eagerly
// would miss every global-pool match.
let _racePowerMap: Map<string, _PoolEntry> | null = null
function _buildRacePowerLookup(): Map<string, _PoolEntry> {
  const m = new Map<string, _PoolEntry>()
  for (const race of races) {
    const pools: { parent: _PoolEntry; entries: { label: string; element?: import('./types').ElementType; grade?: import('./types').ItemGrade }[] }[] = []
    for (const e of (race.subTypePool ?? []))         pools.push({ parent: e, entries: e.powerPool ?? [] })
    for (const e of (race.classPool ?? []))           pools.push({ parent: e, entries: e.powerPool ?? [] })
    for (const e of (race.transformationPool ?? []))  pools.push({ parent: e, entries: e.powerPool ?? [] })
    for (const { parent, entries } of pools) {
      for (const p of entries) {
        if (m.has(p.label)) continue
        const fromGlobal = _powersGlobalLookup.get(p.label)
        const element = p.element ?? fromGlobal?.element ?? parent.element
        const grade   = p.grade   ?? fromGlobal?.grade   ?? parent.grade
        if (element || grade) m.set(p.label, { element, grade })
      }
    }
  }
  return m
}
export const racePowerLookup: Pick<Map<string, _PoolEntry>, 'get' | 'has'> = {
  get(label: string) {
    if (!_racePowerMap) _racePowerMap = _buildRacePowerLookup()
    return _racePowerMap.get(label)
  },
  has(label: string) {
    if (!_racePowerMap) _racePowerMap = _buildRacePowerLookup()
    return _racePowerMap.has(label)
  },
}

// Flat lookup for ability labels across all races (top-level + nested in pool entries).
// Nested abilities now inherit their parent class/subtype/transformation's
// element + grade when their own entry omits them — older race data left
// many abilities bare (e.g. ["Opportunist's Edge", weight: 1]) and the
// lookup previously skipped them entirely. Archetype abilities are
// appended in archetypes.ts via mergeAbilityLookup() so each content
// module can populate the shared map without circular imports.
export const abilityLookup: Map<string, _PoolEntry> = (() => {
  const m = new Map<string, _PoolEntry>()
  function add(label: string, entry: _PoolEntry, parent?: _PoolEntry) {
    if (m.has(label)) return
    const element = entry.element ?? parent?.element
    const grade   = entry.grade   ?? parent?.grade
    if (element || grade) m.set(label, { element, grade })
  }
  for (const race of races) {
    for (const a of race.abilities) add(a.label, a)
    for (const e of (race.subTypePool ?? []))        for (const a of (e.abilities ?? [])) add(a.label, a, e)
    for (const e of (race.classPool ?? []))          for (const a of (e.abilities ?? [])) add(a.label, a, e)
    for (const e of (race.transformationPool ?? [])) for (const a of (e.abilities ?? [])) add(a.label, a, e)
  }
  return m
})()


// Register every race's injected wheels with the central registry at module
// load. Consumers (race-extras splice in +page.svelte / StorySpinView) look
// up segments by (raceLabel, wheelId) and may have them mutated by the
// archetype overlay before rendering.
for (const r of races) {
  bulkRegisterRaceWheels(r.label, r.injectedWheels)
}
